import {
  copyFileSync,
  existsSync,
  mkdirSync,
  readdirSync,
  readFileSync,
  statSync,
  writeFileSync,
} from "node:fs";
import path from "node:path";

const root = process.cwd();

const generatedBanner = (source) =>
  [
    "<!-- Generated by scripts/build-agent-pack.mjs. Do not edit directly. -->",
    `<!-- Source: ${source} -->`,
    "",
  ].join("\n");

function readJson(relativePath) {
  return JSON.parse(readFileSync(path.join(root, relativePath), "utf8"));
}

function readJsonDirectory(relativeDir) {
  const directory = path.join(root, relativeDir);

  return readdirSync(directory)
    .filter((entry) => entry.endsWith(".json"))
    .map((entry) => readJson(path.join(relativeDir, entry).replace(/\\/g, "/")))
    .sort((left, right) => left.name.localeCompare(right.name));
}

function ensureDirectory(relativeDir) {
  mkdirSync(path.join(root, relativeDir), { recursive: true });
}

function writeText(relativePath, content) {
  const target = path.join(root, relativePath);
  ensureDirectory(path.dirname(relativePath));
  writeFileSync(target, content, "utf8");
}

function copyDirectory(sourceRelativeDir, targetRelativeDir) {
  const sourceDir = path.join(root, sourceRelativeDir);
  const targetDir = path.join(root, targetRelativeDir);
  ensureDirectory(targetRelativeDir);

  for (const entry of readdirSync(sourceDir)) {
    const sourcePath = path.join(sourceDir, entry);
    const targetPath = path.join(targetDir, entry);
    const stats = statSync(sourcePath);

    if (stats.isDirectory()) {
      copyDirectory(
        path.join(sourceRelativeDir, entry).replace(/\\/g, "/"),
        path.join(targetRelativeDir, entry).replace(/\\/g, "/")
      );
      continue;
    }

    copyFileSync(sourcePath, targetPath);
  }
}

function bullets(items) {
  return items.map((item) => `- ${item}`).join("\n");
}

function renderClaudeCommand(command, agentsByName) {
  const workflow = command.workflow
    .map((agentName) => {
      const agent = agentsByName.get(agentName);
      const role = agent ? `${agentName} (${agent.role})` : agentName;
      return `- ${role}`;
    })
    .join("\n");

  const inputs = command.inputs
    .map(
      (input) =>
        `- \`${input.name}\`${input.required ? " (required)" : " (optional)"}: ${input.description}`
    )
    .join("\n");

  const sections = command.output.sections.map((section) => `- ${section}`).join("\n");

  return (
    generatedBanner(`agent-pack/core/commands/${command.name}.json`) +
    `# /${command.name}\n\n` +
    `${command.description}\n\n` +
    `## Inputs\n\n${inputs}\n\n` +
    `## Workflow\n\n${workflow}\n\n` +
    `## Required skills\n\n${bullets(command.loadsSkills)}\n\n` +
    `## Required MCP\n\n${bullets(command.requiresMcp)}\n\n` +
    `## Output contract\n\n` +
    `Return ${command.output.format} with these sections:\n\n${sections}\n`
  );
}

function renderClaudeAgent(agent) {
  return (
    generatedBanner(`agent-pack/core/agents/${agent.name}.json`) +
    `# ${agent.name}\n\n` +
    `Role: ${agent.role}\n\n` +
    `Mission: ${agent.mission}\n\n` +
    `## Responsibilities\n\n${bullets(agent.responsibilities)}\n\n` +
    `## Policies\n\n${bullets(agent.usesPolicies)}\n\n` +
    `## Allowed skills\n\n${bullets(agent.allowedSkills)}\n\n` +
    `## Allowed MCP\n\n${bullets(agent.allowedMcp)}\n\n` +
    `## Handoff when\n\n${bullets(agent.handoffWhen)}\n\n` +
    `## Deliverables\n\n${bullets(agent.deliverables)}\n`
  );
}

function renderClaudeRepoGuide(pack, commands, agents, skills, mcpRegistry) {
  const commandList = commands.map((command) => `- \`/${command.name}\`: ${command.description}`).join("\n");
  const agentList = agents.map((agent) => `- \`${agent.name}\`: ${agent.role}`).join("\n");
  const skillList = skills
    .map(
      (skill) =>
        `- \`${skill.name}\`: project-local skill at \`.claude/skills/${skill.name}/SKILL.md\``
    )
    .join("\n");
  const mcpList = mcpRegistry.servers
    .filter((server) => server.hosts.includes("claude-code"))
    .map(
      (server) =>
        `- \`${server.name}\`: ${server.command} ${server.args.join(" ")} (env: ${server.env.join(", ")})`
    )
    .join("\n");

  const appGuideLine = existsSync(path.join(root, "app/CLAUDE.md"))
    ? "- Read `app/CLAUDE.md` before changing application code under `app/`."
    : "";

  return (
    generatedBanner("agent-pack/core") +
    `# CLAUDE.md\n\n` +
    `${pack.displayName} provides the shared Claude Code wiring for this repository.\n\n` +
    `## Source of truth\n\n` +
    `- Edit shared definitions in \`agent-pack/core/\`.\n` +
    `- Edit MCP registrations in \`agent-pack/mcp/registry.json\`.\n` +
    `- Regenerate Claude outputs with \`powershell -ExecutionPolicy Bypass -File scripts/build-agent-pack.ps1\`.\n` +
    `- Do not hand-edit generated files in \`.claude/\` or this file.\n\n` +
    `## Local commands\n\n${commandList}\n\n` +
    `## Local subagents\n\n${agentList}\n\n` +
    `## Local skills\n\n${skillList}\n\n` +
    `## MCP servers to register\n\n${mcpList}\n\n` +
    `## Working rules\n\n` +
    `- Use the generated commands in \`.claude/commands/\` as the user-facing entrypoints.\n` +
    `- Use the generated subagents in \`.claude/agents/\` for role-specific handoffs.\n` +
    `- Load \`repo-conventions\` before changing the agent pack itself.\n` +
    `${appGuideLine}\n`
  );
}

function renderCodexAgents(pack, commands, agents, skills, mcpRegistry) {
  const commandLines = commands
    .map((command) => {
      const workflow = command.workflow.join(" -> ");
      const skillsList = command.loadsSkills.join(", ");
      return `- \`${command.name}\`: ${command.description} Workflow: ${workflow}. Skills: ${skillsList}.`;
    })
    .join("\n");

  const agentLines = agents
    .map(
      (agent) =>
        `- \`${agent.name}\`: ${agent.role}. Mission: ${agent.mission} Deliver: ${agent.deliverables.join(
          " "
        )}`
    )
    .join("\n");

  const skillLines = skills
    .map(
      (skill) =>
        `- \`${skill.name}\`: ${skill.description} Path: \`agent-pack/core/skills/${skill.name}/SKILL.md\`.`
    )
    .join("\n");

  const mcpLines = mcpRegistry.servers
    .map(
      (server) =>
        `- \`${server.name}\`: ${server.description} Command: \`${server.command} ${server.args.join(
          " "
        )}\`.`
    )
    .join("\n");

  return (
    generatedBanner("agent-pack/core") +
    `# AGENTS\n\n` +
    `${pack.displayName} is the source-backed command, agent, skill, and MCP system for this repository.\n\n` +
    `## Source of truth\n\n` +
    `- Edit shared definitions in \`agent-pack/core/\`.\n` +
    `- Edit MCP registrations in \`agent-pack/mcp/registry.json\`.\n` +
    `- Regenerate host outputs with \`node scripts/build-agent-pack.mjs\`.\n` +
    `- Do not hand-edit generated files in \`.claude/\`, \`AGENTS.md\`, or \`agent-pack/dist/\`.\n\n` +
    `## Commands\n\n${commandLines}\n\n` +
    `## Subagents\n\n${agentLines}\n\n` +
    `## Skills\n\n${skillLines}\n\n` +
    `## MCP registry\n\n${mcpLines}\n\n` +
    `## Operating rules\n\n` +
    `- Load \`repo-conventions\` before changing the agent pack.\n` +
    `- Keep commands orchestration-only and push reusable knowledge into skills.\n` +
    `- Prefer the smallest safe change and report validation status clearly.\n`
  );
}

function renderManifest(pack, host, commands, agents, skills, mcpRegistry) {
  return JSON.stringify(
    {
      pack: {
        name: pack.name,
        version: pack.version,
        host,
      },
      commands: commands.map((command) => ({
        name: command.name,
        description: command.description,
        workflow: command.workflow,
        skills: command.loadsSkills,
        mcp: command.requiresMcp,
      })),
      agents: agents.map((agent) => ({
        name: agent.name,
        role: agent.role,
        policies: agent.usesPolicies,
      })),
      skills: skills.map((skill) => ({
        name: skill.name,
        path: `agent-pack/core/skills/${skill.name}/SKILL.md`,
      })),
      mcp: mcpRegistry.servers.filter((server) => server.hosts.includes(host)),
    },
    null,
    2
  );
}

function renderClaudeSetupGuide(mcpRegistry) {
  const serverLines = mcpRegistry.servers
    .filter((server) => server.hosts.includes("claude-code"))
    .map((server) => {
      const envLine = server.env.length ? `Required env vars: ${server.env.join(", ")}.` : "No env vars.";
      return `## ${server.name}\n\n- Command: \`${server.command} ${server.args.join(" ")}\`\n- ${envLine}\n`;
    })
    .join("\n");

  return (
    generatedBanner("agent-pack/mcp/registry.json") +
    `# Claude MCP Setup\n\n` +
    `Use this file as the handoff for registering MCP servers in Claude Code on your machine.\n\n` +
    `${serverLines}`
  );
}

function extractSkillMetadata(skillRootRelative) {
  const raw = readFileSync(path.join(root, skillRootRelative, "SKILL.md"), "utf8");
  const match = raw.match(/^---\n([\s\S]*?)\n---/);

  if (!match) {
    throw new Error(`Missing frontmatter in ${skillRootRelative}/SKILL.md`);
  }

  const metadata = {};
  for (const line of match[1].split("\n")) {
    const separator = line.indexOf(":");
    if (separator === -1) {
      continue;
    }

    const key = line.slice(0, separator).trim();
    const value = line.slice(separator + 1).trim();
    metadata[key] = value;
  }

  return metadata;
}

const pack = readJson("agent-pack/core/pack.json");
const commands = readJsonDirectory("agent-pack/core/commands");
const agents = readJsonDirectory("agent-pack/core/agents");
const mcpRegistry = readJson("agent-pack/mcp/registry.json");
const skillsDirectory = path.join(root, "agent-pack/core/skills");
const skills = readdirSync(skillsDirectory)
  .map((entry) => ({
    ...extractSkillMetadata(`agent-pack/core/skills/${entry}`),
  }))
  .sort((left, right) => left.name.localeCompare(right.name));

const agentsByName = new Map(agents.map((agent) => [agent.name, agent]));

ensureDirectory(".claude/commands");
ensureDirectory(".claude/agents");
ensureDirectory(".claude/skills");
ensureDirectory("agent-pack/dist/claude");
ensureDirectory("agent-pack/dist/codex");

for (const command of commands) {
  writeText(`.claude/commands/${command.name}.md`, renderClaudeCommand(command, agentsByName));
}

for (const agent of agents) {
  writeText(`.claude/agents/${agent.name}.md`, renderClaudeAgent(agent));
}

for (const skill of skills) {
  copyDirectory(
    `agent-pack/core/skills/${skill.name}`,
    `.claude/skills/${skill.name}`
  );
}

writeText("CLAUDE.md", renderClaudeRepoGuide(pack, commands, agents, skills, mcpRegistry));

writeText(
  "AGENTS.md",
  renderCodexAgents(pack, commands, agents, skills, mcpRegistry)
);

writeText(
  "agent-pack/dist/claude/manifest.json",
  renderManifest(pack, "claude-code", commands, agents, skills, mcpRegistry) + "\n"
);
writeText(
  "agent-pack/dist/codex/manifest.json",
  renderManifest(pack, "codex", commands, agents, skills, mcpRegistry) + "\n"
);
writeText(
  "agent-pack/dist/claude/mcp-servers.json",
  JSON.stringify(
    mcpRegistry.servers.filter((server) => server.hosts.includes("claude-code")),
    null,
    2
  ) + "\n"
);
writeText(
  "agent-pack/dist/claude/SETUP.md",
  renderClaudeSetupGuide(mcpRegistry)
);
writeText(
  "agent-pack/dist/codex/mcp-servers.json",
  JSON.stringify(
    mcpRegistry.servers.filter((server) => server.hosts.includes("codex")),
    null,
    2
  ) + "\n"
);
